1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const key = (x: number, y: number) => `${x},${y}`;
10	
11	export function nextGeneration(cells: Cell[]): Cell[] {
12	  const live = new Set(cells.map(([x, y]) => key(x, y)));
13	  const neighborCounts = new Map<string, { cell: Cell; count: number }>();
14	
15	  for (const [x, y] of cells) {
16	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
17	      const cell: Cell = [x + dx, y + dy];
18	      const k = key(cell[0], cell[1]);
19	      const entry = neighborCounts.get(k) ?? { cell, count: 0 };
20	      entry.count++;
21	      neighborCounts.set(k, entry);
22	    }
23	  }
24	
25	  const survives = (k: string, count: number) =>
26	    count === 3 || (count === 2 && live.has(k));
27	
28	  const result: Cell[] = [];
29	  for (const [k, { cell, count }] of neighborCounts) {
30	    if (survives(k, count)) result.push(cell);
31	  }
32	  return result;
33	}
34

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("should return empty array when given empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it.todo("should kill two adjacent live cells (underpopulation)");
12	  it("should keep a block (still life) unchanged", () => {
13	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
14	    const result = nextGeneration(block);
15	    expect(result.sort()).toEqual(block.sort());
16	  });
17	  it("should oscillate a vertical blinker to horizontal", () => {
18	    const vertical: [number, number][] = [[0, 0], [0, 1], [0, 2]];
19	    const horizontal: [number, number][] = [[-1, 1], [0, 1], [1, 1]];
20	    const result = nextGeneration(vertical);
21	    expect(result.sort()).toEqual(horizontal.sort());
22	  });
23	  it("should birth a dead cell with exactly 3 live neighbors (reproduction)", () => {
24	    const input: [number, number][] = [[0, 0], [1, 0], [0, 1]];
25	    const expected: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
26	    const result = nextGeneration(input);
27	    expect(result.sort()).toEqual(expected.sort());
28	  });
29	});
